-- Check grain on transformed table: e.g., after deduping
SELECT COUNT(*) AS transformed_rows, COUNT(DISTINCT order_id) AS unique_ids
FROM orders_dedup WHERE dupe_count IS NOT NULL;

template.minimal:
SELECT numerator / NULLIF(denominator, 0) AS safe_ratio FROM metrics;
-- To handle NULL in numerator too:
SELECT COALESCE(numerator, 0) / NULLIF(COALESCE(denominator, 0), 0) AS safe_ratio FROM metrics;

mistake_patterns.good_sql:
SELECT * FROM t1 JOIN t2 ON (
  (t1.status = t2.status) OR
  (t1.status IS NULL AND t2.status IS NULL)
);

mistake_patterns.detection_sql:
-- Test: filter on order_date in inner vs outer query. If LAG differs, window ran on unfiltered data
WITH outer_filter AS (
  SELECT month, revenue, LAG(revenue) OVER (ORDER BY month) AS prev
  FROM orders WHERE order_date >= '2024-01-01'
)
SELECT prev FROM outer_filter LIMIT 1;

template.minimal:
WITH dedup AS (
  SELECT *,
    ROW_NUMBER() OVER (PARTITION BY key ORDER BY loaded_at DESC) AS rn
  FROM raw_table
)
DELETE FROM raw_table WHERE id IN (SELECT id FROM dedup WHERE rn > 1);
